WITH MEMBER [Measures].[Combined Channel Revenue] AS
    Sum(
        {
            [Sales Channel].[Sales Channel].&[Internet],
            [Sales Channel].[Sales Channel].&[Reseller]
        },
        [Measures].[___Channel Revenue Value]
    )
SELECT {[Measures].[Combined Channel Revenue]} ON COLUMNS
FROM [Adventure Works]

SELECT 
    Aggregate(
        {
            [Sales Channel].[Sales Channel].&[Internet],
            [Sales Channel].[Sales Channel].&[Reseller]
        },
        [Measures].[Reseller Gross Profit Margin]
    ) ON COLUMNS
FROM [Adventure Works]

WITH MEMBER [Measures].[Combined_Channel_Revenue] AS
    Aggregate(
        {
            [Sales Channel].[Sales Channel].&[Internet],
            [Sales Channel].[Sales Channel].&[Reseller]
        },
        [Measures].[Sales Amount]
    )
SELECT [Measures].[Combined_Channel_Revenue] ON COLUMNS
FROM [Adventure Works]

WITH MEMBER [Measures].[Combined Gross Profit Margin] AS
    IIF(
        Aggregate(
            {
                [Sales Channel].[Sales Channel].&[Online],
                [Sales Channel].[Sales Channel].&[Reseller]
            },
            [Measures].[Sales Amount]
        ) = 0,
        NULL,
        Aggregate(
            {
                [Sales Channel].[Sales Channel].&[Online],
                [Sales Channel].[Sales Channel].&[Reseller]
            },
            [Measures].[Gross Profit]
        )
        /
        Aggregate(
            {
                [Sales Channel].[Sales Channel].&[Online],
                [Sales Channel].[Sales Channel].&[Reseller]
            },
            [Measures].[Sales Amount]
        )
    )
SELECT {[Measures].[Combined Gross Profit Margin]} ON COLUMNS
FROM [Adventure Works]

SELECT {[Measures].[Gross Profit Margin]} ON COLUMNS
FROM [Adventure Works]
